mapper.select:
/** UsptExpertAcdmcrDao.selectList */ select expert_acdmcr_id /**전문가학력ID **/ ,expert_id /**전문가ID**/ ,acdmcr_bgnde /**학력시작일**/ ,acdmcr_endde /**학력종료일**/ ,dgri_cd /**학위코드**/ ,dept_nm /**부서명**/ ,ofcps_nm /**직위명**/ ,chrg_job_nm /**담당업무명**/ ,schul_nm /**학교명**/ ,major_nm /**전공명**/ ,profsr_nm /**지도교수명**/ ,grdtn_div_cd /**졸업구분코드(G:GRDTN_DIV)**/ ,creator_id /**생성자ID(CMMT_MEMBER.MEMBER_ID)**/ ,created_dt /**생성일시**/ ,updater_id /**수정자ID(CMMT_MEMBER.MEMBER_ID)**/ ,updated_dt /**수정일시**/ from uspt_expert_acdmcr where 1=1
and expert_acdmcr_id = #{expertAcdmcrId}
and expert_id = #{expertId}

mapper.update:
/** UsptExpertAcdmcrDao.update */
update uspt_expert_acdmcr
	  set	 acdmcr_bgnde          = #{acdmcrBgnde}
			, acdmcr_endde          = #{acdmcrEndde}
			, dgri_cd                   = #{dgriCd}
			, dept_nm                 = #{deptNm}
			, ofcps_nm                 = #{ofcpsNm}
			, chrg_job_nm              = #{chrgJobNm}
			, schul_nm                 = #{schulNm}
			, major_nm                  = #{majorNm}
			, profsr_nm                 = #{profsrNm}
			, grdtn_div_cd              = #{grdtnDivCd}
			, updater_id                = #{updaterId}
			, updated_dt                = #{updatedDt}
where expert_acdmcr_id  = #{expertAcdmcrId}
  and  expert_id             = #{expertId}

